func (e *executableSchema) Exec(ctx context.Context) graphql.ResponseHandler {
	opCtx := graphql.GetOperationContext(ctx)
	ec := executionContext{opCtx, e, 0, 0, make(chan graphql.DeferredResult)}
	inputUnmarshalMap := graphql.BuildUnmarshalerMap(
		ec.unmarshalInputAddEmailTemplateRequest,
		ec.unmarshalInputAddOrgMemberRequest,
		ec.unmarshalInputAddTrustedIssuerRequest,
		ec.unmarshalInputAddVerifiedOrgDomainRequest,
		ec.unmarshalInputAddWebhookRequest,
		ec.unmarshalInputAdminLoginRequest,
		ec.unmarshalInputAdminSignupRequest,
		ec.unmarshalInputCheckPermissionsInput,
		ec.unmarshalInputClientRequest,
		ec.unmarshalInputCreateClientRequest,
		ec.unmarshalInputCreateOrgOIDCConnectionRequest,
		ec.unmarshalInputCreateOrgSAMLConnectionRequest,
		ec.unmarshalInputCreateOrganizationRequest,
		ec.unmarshalInputCreateScimEndpointRequest,
		ec.unmarshalInputDeleteEmailTemplateRequest,
		ec.unmarshalInputDeleteOrgDomainRequest,
		ec.unmarshalInputDeleteUserRequest,
		ec.unmarshalInputFgaExpandInput,
		ec.unmarshalInputFgaListUsersInput,
		ec.unmarshalInputFgaReadTuplesInput,
		ec.unmarshalInputFgaRelationInput,
		ec.unmarshalInputFgaTupleInput,
		ec.unmarshalInputFgaWriteModelInput,
		ec.unmarshalInputFgaWriteTuplesInput,
		ec.unmarshalInputForgotPasswordRequest,
		ec.unmarshalInputGenerateJWTKeysRequest,
		ec.unmarshalInputGetUserRequest,
		ec.unmarshalInputInviteMemberRequest,
		ec.unmarshalInputListAuditLogRequest,
		ec.unmarshalInputListClientsRequest,
		ec.unmarshalInputListOrgDomainsRequest,
		ec.unmarshalInputListOrgMembersRequest,
		ec.unmarshalInputListOrganizationsRequest,
		ec.unmarshalInputListPermissionsInput,
		ec.unmarshalInputListTrustedIssuersRequest,
		ec.unmarshalInputListWebhookLogRequest,
		ec.unmarshalInputLoginRequest,
		ec.unmarshalInputMagicLinkLoginRequest,
		ec.unmarshalInputMobileLoginRequest,
		ec.unmarshalInputMobileSignUpRequest,
		ec.unmarshalInputOAuthRevokeRequest,
		ec.unmarshalInputOrgOIDCConnectionRequest,
		ec.unmarshalInputOrgSAMLConnectionRequest,
		ec.unmarshalInputOrganizationRequest,
		ec.unmarshalInputPaginatedRequest,
		ec.unmarshalInputPaginationRequest,
		ec.unmarshalInputPermissionCheckInput,
		ec.unmarshalInputRemoveOrgMemberRequest,
		ec.unmarshalInputRequestOrgDomainRequest,
		ec.unmarshalInputResendOTPRequest,
		ec.unmarshalInputResendVerifyEmailRequest,
		ec.unmarshalInputResetPasswordRequest,
		ec.unmarshalInputScimEndpointRequest,
		ec.unmarshalInputSessionQueryRequest,
		ec.unmarshalInputSignUpRequest,
		ec.unmarshalInputTestEndpointRequest,
		ec.unmarshalInputTrustedIssuerRequest,
		ec.unmarshalInputUpdateAccessRequest,
		ec.unmarshalInputUpdateClientRequest,
		ec.unmarshalInputUpdateEmailTemplateRequest,
		ec.unmarshalInputUpdateEnvRequest,
		ec.unmarshalInputUpdateOrgOIDCConnectionRequest,
		ec.unmarshalInputUpdateOrgSAMLConnectionRequest,
		ec.unmarshalInputUpdateOrganizationRequest,
		ec.unmarshalInputUpdateProfileRequest,
		ec.unmarshalInputUpdateTrustedIssuerRequest,
		ec.unmarshalInputUpdateUserRequest,
		ec.unmarshalInputUpdateWebhookRequest,
		ec.unmarshalInputValidateJWTTokenRequest,
		ec.unmarshalInputValidateSessionRequest,
		ec.unmarshalInputVerifyEmailRequest,
		ec.unmarshalInputVerifyOTPRequest,
		ec.unmarshalInputVerifyOrgDomainRequest,
		ec.unmarshalInputWebhookRequest,
	)
	first := true

	switch opCtx.Operation.Operation {
	case ast.Query:
		return func(ctx context.Context) *graphql.Response {
			var response graphql.Response
			var data graphql.Marshaler
			if first {
				first = false
				ctx = graphql.WithUnmarshalerMap(ctx, inputUnmarshalMap)
				data = ec._Query(ctx, opCtx.Operation.SelectionSet)
			} else {
				if atomic.LoadInt32(&ec.pendingDeferred) > 0 {
					result := <-ec.deferredResults
					atomic.AddInt32(&ec.pendingDeferred, -1)
					data = result.Result
					response.Path = result.Path
					response.Label = result.Label
					response.Errors = result.Errors
				} else {
					return nil
				}
			}
			var buf bytes.Buffer
			data.MarshalGQL(&buf)
			response.Data = buf.Bytes()
			if atomic.LoadInt32(&ec.deferred) > 0 {
				hasNext := atomic.LoadInt32(&ec.pendingDeferred) > 0
				response.HasNext = &hasNext
			}

			return &response
		}
	case ast.Mutation:
		return func(ctx context.Context) *graphql.Response {
			if !first {
				return nil
			}
			first = false
			ctx = graphql.WithUnmarshalerMap(ctx, inputUnmarshalMap)
			data := ec._Mutation(ctx, opCtx.Operation.SelectionSet)
			var buf bytes.Buffer
			data.MarshalGQL(&buf)

			return &graphql.Response{
				Data: buf.Bytes(),
			}
		}

	default:
		return graphql.OneShot(graphql.ErrorResponse(ctx, "unsupported GraphQL operation"))
	}
}

type executionContext struct {
	*graphql.OperationContext
	*executableSchema
	deferred        int32
	pendingDeferred int32
	deferredResults chan graphql.DeferredResult
}

func (ec *executionContext) processDeferredGroup(dg graphql.DeferredGroup) {
	atomic.AddInt32(&ec.pendingDeferred, 1)
	go func() {
		ctx := graphql.WithFreshResponseContext(dg.Context)
		dg.FieldSet.Dispatch(ctx)
		ds := graphql.DeferredResult{
			Path:   dg.Path,
			Label:  dg.Label,
			Result: dg.FieldSet,
			Errors: graphql.GetErrors(ctx),
		}
		// null fields should bubble up
		if dg.FieldSet.Invalids > 0 {
			ds.Result = graphql.Null
		}
		ec.deferredResults <- ds
	}()
}

func (ec *executionContext) introspectSchema() (*introspection.Schema, error) {
	if ec.DisableIntrospection {
		return nil, errors.New("introspection disabled")
	}
	return introspection.WrapSchema(ec.Schema()), nil
}

func (ec *executionContext) introspectType(name string) (*introspection.Type, error) {
	if ec.DisableIntrospection {
		return nil, errors.New("introspection disabled")
	}
	return introspection.WrapTypeFromDef(ec.Schema(), ec.Schema().Types[name]), nil
}

